### Step 3: Implement the token bucket algorithm

Create `rate_limiter.go` to implement the token bucket algorithm:

```go
package main

import (
    "net/http"
    "strconv"
    "sync"
    "time"

    "github.com/go-chi/chi/v5"
)

type TokenBucket struct {
    mu          sync.Mutex
    capacity    int
    tokens      int
    lastRefill  time.Time
    redisKey    string
}

func NewTokenBucket(capacity int, redisKey string) *TokenBucket {
    return &TokenBucket{
        capacity: capacity,
        tokens:   capacity,
        redisKey: redisKey,
    }
}

func (tb *TokenBucket) Allow() bool {
    tb.mu.Lock()
    defer tb.mu.Unlock()

    now := time.Now()
    elapsed := now.Sub(tb.lastRefill)
    tb.lastRefill = now

    refill := int(elapsed.Seconds() * float64(tb.capacity) / 60)
    tb.tokens = min(tb.capacity, tb.tokens+refill)

    if tb.tokens > 0 {
        tb.tokens--
        return true
    }
    return false
}

func min(a, b int) int {
    if a < b {
        return a
    }
    return b
}
```

### Step 4: Create the middleware for the chi router

Modify `main.go` to set up the chi router and the rate limiter middleware:

```go
package main

import (
    "net/http"
    "strconv"

    "github.com/go-chi/chi/v5"
    "github.com/go-chi/chi/v5/middleware"
)

func main() {
    initRedis()

    r := chi.NewRouter()
    r.Use(middleware.Logger)
    r.Use(RateLimiterMiddleware(100, "rate_limit:"))

    r.Get("/", func(w http.ResponseWriter, r *http.Request) {
        w.Write([]byte("Hello, World!"))
    })

    http.ListenAndServe(":8080", r)
}

func RateLimiterMiddleware(capacity int, prefix string) func(http.Handler) http.Handler {
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            ip := r.RemoteAddr
            redisKey := prefix + ip

            // Try to get the token bucket from Redis
            tokens, err := rdb.Get(ctx, redisKey).Int()
            if err != nil {
                // Fallback to in-memory token bucket
                tb := NewTokenBucket(capacity, redisKey)
                if tb.Allow() {
                    next.ServeHTTP(w, r)
                } else {
                    http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
                }
                return
            }

            // Use Redis-backed token bucket
            tb := &TokenBucket{
                capacity: capacity,
                tokens:   tokens,
                redisKey: redisKey,
            }
            if tb.Allow() {
                // Update tokens in Redis
                rdb.Set(ctx, redisKey, tb.tokens, 0)
                next.ServeHTTP(w, r)
            } else {
                http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
            }
        })
    }
}
```

